import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { plainToInstance } from 'class-transformer';
import { validate, ValidationError } from 'class-validator';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { CompanyBaseDto } from '@modules/company/dto/company.base.dto';
import { ICompanyBase } from '@modules/company/types/company.base.interface';
import { ICompanyCreate } from '@modules/company/types/company.create.interface';
import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';

import { TABLE_NAME_COMPANIES } from '@constants/db.constant';

@Injectable()
export class CompanyModel {
	private readonly logger = new Logger(CompanyModel.name);
	private readonly tableName = TABLE_NAME_COMPANIES;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async findById({
		companyId,
	}: {
		companyId: ICompanyBase['_id'];
	}): Promise<ICompanyBase | null> {
		try {
			const result = await this.knexRead<ICompanyBase>(this.tableName)
				.where({ _id: companyId })
				.whereNull('deleted_at')
				.first();

			if (!result) {
				return null;
			}

			const dto = plainToInstance(CompanyBaseDto, result);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for company data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
			}

			return result;
		} catch (error) {
			this.logger.error(
				`Failed to find company by id ${companyId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async create({ data }: { data: ICompanyCreate }): Promise<ICompanyBase> {
		try {
			const dto = plainToInstance(CompanyBaseDto, data);
			const errors = await validate(dto, { skipMissingProperties: true });
			if (errors.length > 0) {
				this.logger.error(
					`Validation failed for company data: ${this.formatValidationErrors({ errors })}`,
				);
				throw new Error(`Validation failed: ${this.formatValidationErrors({ errors })}`);
			}

			const _id = randomUUID();
			const [created] = await this.knexWrite<ICompanyBase>(this.tableName)
				.insert({
					_id,
					...data,
					created_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				})
				.returning('*');

			if (!created) {
				throw new Error('Failed to create company');
			}

			this.logger.debug(`Created company with id ${_id}`);
			return created;
		} catch (error) {
			this.logger.error(`Failed to create company: ${(error as Error).message}`);
			throw error;
		}
	}

	async softDelete({ companyId }: { companyId: ICompanyBase['_id'] }): Promise<void> {
		try {
			await this.knexWrite<ICompanyBase>(this.tableName)
				.where({ _id: companyId })
				.whereNull('deleted_at')
				.update({
					deleted_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Soft deleted company ${companyId}`);
		} catch (error) {
			this.logger.error(
				`Failed to soft delete company ${companyId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	private formatValidationErrors({ errors }: { errors: ValidationError[] }): string {
		return errors
			.map(
				(error) =>
					`${error.property}: ${Object.values(error.constraints ?? {}).join(', ')}`,
			)
			.join('; ');
	}
}

