import { Logger } from '@nestjs/common';

import { TABLE_NAME_COMPANIES } from '@constants/db.constant';

import type { Knex } from 'knex';

const logger = new Logger('20260322120001_create_companies_table.ts');

export async function up(knex: Knex): Promise<void> {
	logger.log('Creating companies table');

	await knex.transaction(async (trx) => {
		const tableExists = await trx.schema.hasTable(TABLE_NAME_COMPANIES);

		if (!tableExists) {
			await trx.schema.createTable(TABLE_NAME_COMPANIES, (table) => {
				table.uuid('_id').primary().notNullable();
				table.string('name', 255).notNullable();
				table
					.timestamp('created_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();
				table
					.timestamp('updated_at', { useTz: true })
					.defaultTo(trx.fn.now())
					.notNullable();
				table.timestamp('deleted_at', { useTz: true }).nullable();
			});

			logger.log('Successfully created companies table');
		} else {
			logger.log('companies table already exists, skipping');
		}
	});
}

export async function down(knex: Knex): Promise<void> {
	logger.log('Dropping companies table');

	await knex.transaction(async (trx) => {
		await trx.schema.dropTableIfExists(TABLE_NAME_COMPANIES);
	});
}

