import { Logger } from '@nestjs/common';
import { Transform, plainToInstance } from 'class-transformer';
import {
	IsBoolean,
	IsEnum,
	IsNotEmpty,
	IsNumber,
	IsString,
	Length,
	Max,
	Min,
	MinLength,
	validateSync,
} from 'class-validator';

import { Environment } from '@interfaces/env-variables.interface';

class EnvironmentVariables {
	@IsEnum(Environment)
	NODE_ENV: Environment;

	@IsNumber()
	@Min(0)
	@Max(65535)
	PORT: number;

	@IsString()
	@IsNotEmpty()
	GLOBAL_PREFIX: string;

	@IsString()
	@IsNotEmpty()
	SERVER_NAME: string;

	@IsBoolean()
	IS_COMPACT_LOGS: boolean;

	@IsBoolean()
	IS_JSON_LIKE_LOGS: boolean;

	@IsNumber()
	@Min(0)
	@Max(60000)
	GRACEFUL_SHUTDOWN_DELAY: number;

	@IsString()
	@IsNotEmpty()
	DATABASE_URL: string;

	@IsString()
	@IsNotEmpty()
	DATABASE_URL_READ_REPLICA: string;

	@IsString()
	@IsNotEmpty()
	REDIS_URL: string;

	@IsString()
	@IsNotEmpty()
	REDIS_READ_URL: string;

	@IsString()
	@MinLength(32)
	JWT_SECRET: string;

	@Transform(({ value }) => Number(value))
	@IsNumber()
	@Min(60)
	JWT_ACCESS_TOKEN_EXPIRY: number;

	@Transform(({ value }) => Number(value))
	@IsNumber()
	@Min(1)
	JWT_REFRESH_TOKEN_EXPIRY_DAYS: number;

	@IsString()
	@IsNotEmpty()
	GITHUB_CLIENT_ID: string;

	@IsString()
	@IsNotEmpty()
	GITHUB_CLIENT_SECRET: string;

	@IsString()
	@IsNotEmpty()
	GITHUB_CALLBACK_URL: string;

	@IsString()
	@IsNotEmpty()
	GOOGLE_CLIENT_ID: string;

	@IsString()
	@IsNotEmpty()
	GOOGLE_CLIENT_SECRET: string;

	@IsString()
	@IsNotEmpty()
	GOOGLE_CALLBACK_URL: string;

	@IsString()
	@IsNotEmpty()
	FRONTEND_URL: string;

	@IsString()
	@Length(64, 64)
	ENCRYPTION_KEY: string;
}

export function validate({
	envConfig,
}: {
	envConfig: Record<string, unknown>;
}): EnvironmentVariables {
	const validatedConfig = plainToInstance(EnvironmentVariables, envConfig, {
		enableImplicitConversion: true,
	});

	const errors = validateSync(validatedConfig, {
		skipMissingProperties: false,
		forbidUnknownValues: true,
		stopAtFirstError: true,
		forbidNonWhitelisted: true,
	});

	if (errors.length > 0) {
		Logger.error('Config validation error', errors);
		throw new Error(errors.toString());
	}

	return validatedConfig;
}

