import { MiddlewareConsumer, Module, NestModule } from '@nestjs/common';
import { APP_GUARD } from '@nestjs/core';
import { ThrottlerModule } from '@nestjs/throttler';

import { AuthModule } from '@modules/auth/auth.module';
import { AuthGuard } from '@modules/auth/guards/auth.guard';
import { FastifyThrottlerGuard } from '@modules/auth/guards/fastify-throttler.guard';
import { RolesGuard } from '@modules/auth/guards/roles.guard';
import { CacheModule } from '@modules/cache/cache.module';
import { CompanyModule } from '@modules/company/company.module';
import { CompanyMemberModule } from '@modules/company-member/company-member.module';
import { DbModule } from '@modules/db/db.module';
import { EnvConfigModule } from '@modules/env-config/env-config.module';
import { HealthModule } from '@modules/health/health.module';
import { InvitationModule } from '@modules/invitation/invitation.module';
import { SessionModule } from '@modules/session/session.module';
import { UserModule } from '@modules/user/user.module';

import { CorrelationIdMiddleware } from '@middlewares/correlation-id.middleware';

@Module({
	imports: [
		EnvConfigModule,
		HealthModule,
		DbModule,
		CacheModule,
		ThrottlerModule.forRoot([{ ttl: 60000, limit: 60 }]),
		AuthModule,
		UserModule,
		CompanyModule,
		CompanyMemberModule,
		InvitationModule,
		SessionModule,
	],
	controllers: [],
	providers: [
		{ provide: APP_GUARD, useClass: AuthGuard },
		{ provide: APP_GUARD, useClass: RolesGuard },
		{ provide: APP_GUARD, useClass: FastifyThrottlerGuard },
	],
})
export class AppModule implements NestModule {
	configure(consumer: MiddlewareConsumer): void {
		consumer.apply(CorrelationIdMiddleware).forRoutes('*path');
	}
}

