import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import { IGithubApiRepo } from '@modules/github/types/github-api.interface';
import { IGithubRepoBase } from '@modules/github/types/github-repo.interface';

import { TABLE_NAME_GITHUB_REPOS } from '@constants/db.constant';

@Injectable()
export class GithubRepoModel {
	private readonly logger = new Logger(GithubRepoModel.name);
	private readonly tableName = TABLE_NAME_GITHUB_REPOS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async upsertMany({
		installationId,
		repos,
	}: {
		installationId: string;
		repos: IGithubApiRepo[];
	}): Promise<void> {
		if (repos.length === 0) return;

		try {
			const rows = repos.map((repo) => ({
				_id: randomUUID(),
				installation_id: installationId,
				github_repo_id: repo.id,
				name: repo.name,
				full_name: repo.full_name,
				private: repo.private,
				default_branch: repo.default_branch,
				created_at: this.knexWrite.fn.now(),
				updated_at: this.knexWrite.fn.now(),
			}));

			await this.knexWrite<IGithubRepoBase>(this.tableName)
				.insert(rows)
				.onConflict('github_repo_id')
				.merge([
					'installation_id',
					'name',
					'full_name',
					'private',
					'default_branch',
					'updated_at',
				]);

			this.logger.debug(`Upserted ${repos.length} repos for installation ${installationId}`);
		} catch (error) {
			this.logger.error(
				`Failed to upsert repos for installation ${installationId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async findByInstallationId({
		installationId,
	}: {
		installationId: string;
	}): Promise<IGithubRepoBase[]> {
		try {
			return await this.knexRead<IGithubRepoBase>(this.tableName)
				.where({ installation_id: installationId })
				.select('*');
		} catch (error) {
			this.logger.error(
				`Failed to find repos for installation ${installationId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async removeByGithubIds({
		installationId,
		githubRepoIds,
	}: {
		installationId: string;
		githubRepoIds: number[];
	}): Promise<void> {
		if (githubRepoIds.length === 0) return;

		try {
			await this.knexWrite<IGithubRepoBase>(this.tableName)
				.where({ installation_id: installationId })
				.whereIn('github_repo_id', githubRepoIds)
				.delete();

			this.logger.debug(
				`Removed ${githubRepoIds.length} repos from installation ${installationId}`,
			);
		} catch (error) {
			this.logger.error(
				`Failed to remove repos from installation ${installationId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}
}
