} from '@constants/env-variables.constant';

const GITHUB_TOKEN_TTL_MS = 55 * 60 * 1000;

@Injectable()
export class GithubAppService {
	private readonly logger = new Logger(GithubAppService.name);

	constructor(
		private readonly configService: EnvConfigService,
		private readonly cacheService: CacheService,
		private readonly httpService: HttpService,
	) {}

	generateAppJwt(): string {
		const appId = this.configService.get<string>({ key: GITHUB_APP_ID });
		const rawKey = this.configService.get<string>({ key: GITHUB_APP_PRIVATE_KEY });
		const privateKey = rawKey.replace(/\\n/g, '\n');

		const now = Math.floor(Date.now() / 1000);
		const header = Buffer.from(JSON.stringify({ alg: 'RS256', typ: 'JWT' })).toString('base64url');
		const payload = Buffer.from(
			JSON.stringify({ iat: now - 60, exp: now + 600, iss: appId }),
		).toString('base64url');
		const data = `${header}.${payload}`;

		const sign = createSign('RSA-SHA256');
		sign.update(data);
		const signature = sign.sign(privateKey, 'base64url');

		return `${data}.${signature}`;
	}

	async getInstallationToken({ installationId }: { installationId: number }): Promise<string> {
		const cached = await this.cacheService.get<string>({
			namespace: Namespaces.GITHUB_TOKEN,
			key: String(installationId),
			consistencyLevel: ConsistencyLevel.STRONG,
		});

		if (cached) {
			return cached;
		}

		const jwt = this.generateAppJwt();
		const { data } = await this.httpService.axiosRef.post<IGithubApiInstallationToken>(
			`https://api.github.com/app/installations/${installationId}/access_tokens`,
			{},
			{
				headers: {
					Authorization: `Bearer ${jwt}`,
					Accept: 'application/vnd.github+json',
					'X-GitHub-Api-Version': '2022-11-28',
				},
			},
		);

		await this.cacheService.set({
			namespace: Namespaces.GITHUB_TOKEN,
			key: String(installationId),
			value: data.token,
			ttl: GITHUB_TOKEN_TTL_MS,
		});

		this.logger.debug(`Generated installation token for installation ${installationId}`);
		return data.token;
	}

	async getInstallation({
		installationId,
	}: {
		installationId: number;
	}): Promise<IGithubApiInstallation> {
		const jwt = this.generateAppJwt();
		const { data } = await this.httpService.axiosRef.get<IGithubApiInstallation>(
			`https://api.github.com/app/installations/${installationId}`,
			{
				headers: {
					Authorization: `Bearer ${jwt}`,
					Accept: 'application/vnd.github+json',
					'X-GitHub-Api-Version': '2022-11-28',
				},
			},
		);

		return data;
	}

	async listInstallationRepos({
		installationId,
	}: {
		installationId: number;
	}): Promise<IGithubApiRepo[]> {
		const token = await this.getInstallationToken({ installationId });
		const { data } = await this.httpService.axiosRef.get<IGithubApiReposListResponse>(
			'https://api.github.com/installation/repositories',
			{
				headers: {
					Authorization: `token ${token}`,
					Accept: 'application/vnd.github+json',
					'X-GitHub-Api-Version': '2022-11-28',
				},
			},
		);

		return data.repositories;
	}
}
