import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import {
	GithubInstallationStatus,
	IGithubInstallationBase,
	IGithubInstallationCreate,
} from '@modules/github/types/github-installation.interface';

import { TABLE_NAME_GITHUB_INSTALLATIONS } from '@constants/db.constant';

@Injectable()
export class GithubInstallationModel {
	private readonly logger = new Logger(GithubInstallationModel.name);
	private readonly tableName = TABLE_NAME_GITHUB_INSTALLATIONS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async create({ data }: { data: IGithubInstallationCreate }): Promise<IGithubInstallationBase> {
		try {
			const _id = randomUUID();
			const [created] = await this.knexWrite<IGithubInstallationBase>(this.tableName)
				.insert({
					_id,
					...data,
					status: GithubInstallationStatus.ACTIVE,
					installed_at: this.knexWrite.fn.now(),
					created_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				})
				.returning('*');

			if (!created) {
				throw new Error('Failed to create github installation');
			}

			this.logger.debug(`Created github installation ${_id}`);
			return created;
		} catch (error) {
			this.logger.error(`Failed to create github installation: ${(error as Error).message}`);
			throw error;
		}
	}

	async findByInstallationId({
		installationId,
	}: {
		installationId: number;
	}): Promise<IGithubInstallationBase | null> {
		try {
			const result = await this.knexRead<IGithubInstallationBase>(this.tableName)
				.where({ installation_id: installationId })
				.first();

			return result ?? null;
		} catch (error) {
			this.logger.error(
				`Failed to find installation by installation_id ${installationId}: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async markUninstalled({ installationId }: { installationId: number }): Promise<void> {
		try {
			await this.knexWrite<IGithubInstallationBase>(this.tableName)
				.where({ installation_id: installationId })
				.update({
					status: GithubInstallationStatus.UNINSTALLED,
					uninstalled_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Marked installation ${installationId} as uninstalled`);
		} catch (error) {
			this.logger.error(
				`Failed to mark installation ${installationId} as uninstalled: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async markSuspended({ installationId }: { installationId: number }): Promise<void> {
		try {
			await this.knexWrite<IGithubInstallationBase>(this.tableName)
				.where({ installation_id: installationId })
				.update({
					status: GithubInstallationStatus.SUSPENDED,
					suspended_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Marked installation ${installationId} as suspended`);
		} catch (error) {
			this.logger.error(
				`Failed to mark installation ${installationId} as suspended: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async markActive({ installationId }: { installationId: number }): Promise<void> {
		try {
			await this.knexWrite<IGithubInstallationBase>(this.tableName)
				.where({ installation_id: installationId })
				.update({
					status: GithubInstallationStatus.ACTIVE,
					suspended_at: null,
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Marked installation ${installationId} as active`);
		} catch (error) {
			this.logger.error(
				`Failed to mark installation ${installationId} as active: ${(error as Error).message}`,
			);
			throw error;
		}
	}

	async markUninstalledByDbId({
		id,
		companyId,
	}: {
		id: string;
		companyId: string;
	}): Promise<void> {
		try {
			await this.knexWrite<IGithubInstallationBase>(this.tableName)
				.where({ _id: id, company_id: companyId })
				.update({
					status: GithubInstallationStatus.UNINSTALLED,
					uninstalled_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});

			this.logger.debug(`Marked installation ${id} as uninstalled`);
		} catch (error) {
			this.logger.error(
				`Failed to mark installation ${id} as uninstalled: ${(error as Error).message}`,
			);
			throw error;
		}
	}
}
