import { randomUUID } from 'node:crypto';

import { BadRequestException, Injectable, Logger } from '@nestjs/common';

import { CacheService } from '@modules/cache/cache.service';
import { Namespaces } from '@modules/cache/types/cache.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
import { GithubRepoModel } from '@modules/github/db/github-repos.model';
import { GithubAppService } from '@modules/github/github-app.service';
import { IGithubInstallationBase } from '@modules/github/types/github-installation.interface';

import { GITHUB_APP_NAME } from '@constants/env-variables.constant';

interface IInstallStateValue {
	companyId: string;
	userId: string;
}

const STATE_TTL_MS = 5 * 60 * 1000;

@Injectable()
export class GithubInstallService {
	private readonly logger = new Logger(GithubInstallService.name);

	constructor(
		private readonly configService: EnvConfigService,
		private readonly cacheService: CacheService,
		private readonly githubAppService: GithubAppService,
		private readonly githubInstallationModel: GithubInstallationModel,
		private readonly githubRepoModel: GithubRepoModel,
	) {}

	async initiateConnect({
		companyId,
		userId,
	}: {
		companyId: string;
		userId: string;
	}): Promise<string> {
		const state = randomUUID();

		await this.cacheService.set({
			namespace: Namespaces.GITHUB_INSTALL_STATE,
			key: state,
			value: { companyId, userId } satisfies IInstallStateValue,
			ttl: STATE_TTL_MS,
		});

		const appName = this.configService.get<string>({ key: GITHUB_APP_NAME });
		return `https://github.com/apps/${appName}/installations/new?state=${state}`;
	}

	async handleCallback({
		installationId,
		state,
	}: {
		installationId: number;
		state: string;
	}): Promise<IGithubInstallationBase> {
		const stateData = await this.cacheService.get<IInstallStateValue>({
			namespace: Namespaces.GITHUB_INSTALL_STATE,
			key: state,
		});

		if (!stateData) {
			throw new BadRequestException('Invalid or expired state token');
		}

		await this.cacheService.deleteOne({
			namespace: Namespaces.GITHUB_INSTALL_STATE,
			key: state,
		});

		const githubInstall = await this.githubAppService.getInstallation({ installationId });

		const installation = await this.githubInstallationModel.create({
			data: {
				company_id: stateData.companyId,
				installation_id: installationId,
				org_login: githubInstall.account.login,
				org_id: githubInstall.account.id,
			},
		});

		void this.syncRepos({
			installationId,
			installationDbId: installation._id,
		});

		return installation;
	}

	async disconnect({
		installationDbId,
		companyId,
	}: {
		installationDbId: string;
		companyId: string;
	}): Promise<void> {
		await this.githubInstallationModel.markUninstalledByDbId({
			id: installationDbId,
			companyId,
		});

		this.logger.debug(`Disconnected installation ${installationDbId} for company ${companyId}`);
	}

	private async syncRepos({
		installationId,
		installationDbId,
	}: {
		installationId: number;
		installationDbId: string;
	}): Promise<void> {
		try {
			const repos = await this.githubAppService.listInstallationRepos({ installationId });
			await this.githubRepoModel.upsertMany({ installationId: installationDbId, repos });
			this.logger.debug(`Synced ${repos.length} repos for installation ${installationDbId}`);
		} catch (error) {
			this.logger.error(
				`Failed to sync repos for installation ${installationDbId}: ${(error as Error).message}`,
			);
		}
	}
}
