import { createHmac, timingSafeEqual } from 'node:crypto';

import { InjectQueue } from '@nestjs/bullmq';
import { Injectable, Logger } from '@nestjs/common';
import { Queue } from 'bullmq';

import { EnvConfigService } from '@modules/env-config/env-config.service';
import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
import { IGithubInstallationEvent } from '@modules/github/types/github-api.interface';
import { GithubInstallationStatus } from '@modules/github/types/github-installation.interface';

import { GITHUB_APP_WEBHOOK_SECRET } from '@constants/env-variables.constant';

@Injectable()
export class GithubWebhookService {
	private readonly logger = new Logger(GithubWebhookService.name);

	constructor(
		private readonly configService: EnvConfigService,
		private readonly githubInstallationModel: GithubInstallationModel,
		@InjectQueue('github') private readonly githubQueue: Queue,
	) {}

	verifySignature({
		payload,
		signature,
	}: {
		payload: string;
		signature: string;
	}): boolean {
		const secret = this.configService.get<string>({ key: GITHUB_APP_WEBHOOK_SECRET });
		const computed = `sha256=${createHmac('sha256', secret).update(payload).digest('hex')}`;

		const trusted = Buffer.from(signature);
		const untrusted = Buffer.from(computed);

		if (trusted.length !== untrusted.length) return false;
		return timingSafeEqual(trusted, untrusted);
	}

	async handleEvent({
		event,
		installationId,
		payload,
	}: {
		event: string;
		installationId: number;
		payload: unknown;
	}): Promise<void> {
		const installation = await this.githubInstallationModel.findByInstallationId({
			installationId,
		});

		if (!installation) {
			this.logger.warn(`Webhook received for unknown installation: ${installationId}`);
			return;
		}

		if (installation.status === GithubInstallationStatus.UNINSTALLED) {
			this.logger.warn(`Webhook received for uninstalled installation: ${installationId}`);
			return;
		}

		if (event === 'installation') {
			await this.handleInstallationLifecycle({
				installationId,
				payload: payload as IGithubInstallationEvent,
			});
			return;
		}

		if (installation.status === GithubInstallationStatus.SUSPENDED) {
			this.logger.warn(`Dropping event for suspended installation: ${installationId}`);
			return;
		}

		await this.githubQueue.add('raw_event', {
			event,
			installationId,
			payload,
			receivedAt: new Date(),
		});

		this.logger.debug(`Queued ${event} event for installation ${installationId}`);
	}

	private async handleInstallationLifecycle({
		installationId,
		payload,
	}: {
		installationId: number;
		payload: IGithubInstallationEvent;
	}): Promise<void> {
		if (payload.action === 'deleted') {
			await this.githubInstallationModel.markUninstalled({ installationId });
			this.logger.debug(`Installation ${installationId} uninstalled`);
		} else if (payload.action === 'suspend') {
			await this.githubInstallationModel.markSuspended({ installationId });
			this.logger.debug(`Installation ${installationId} suspended`);
		} else if (payload.action === 'unsuspend') {
			await this.githubInstallationModel.markActive({ installationId });
			this.logger.debug(`Installation ${installationId} unsuspended`);
		}
	}
}
