```typescript
import {
	Body,
	Controller,
	Headers,
	HttpCode,
	HttpStatus,
	Post,
	UnauthorizedException,
} from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';

import { Public } from '@modules/auth/decorators/public.decorator';
import { GithubWebhookService } from '@modules/github/github-webhook.service';

import { LogExecution } from '@decorators/log-execution.decorator';

@ApiTags('GitHub Webhooks')
@Controller('integrations/github')
export class GithubWebhookController {
	constructor(private readonly githubWebhookService: GithubWebhookService) {}

	@Post('webhook')
	@Public()
	@HttpCode(HttpStatus.OK)
	@ApiOperation({ summary: 'Receive GitHub App webhook events' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Event received' })
	@ApiResponse({ status: HttpStatus.UNAUTHORIZED, description: 'Invalid signature' })
	@LogExecution()
	async handleWebhook(
		@Headers() headers: Record<string, string>,
		@Body() rawBody: string,
	): Promise<void> {
		const signature = headers['x-hub-signature-256'] ?? '';
		const event = headers['x-github-event'] ?? '';
		const installationIdRaw = headers['x-github-hook-installation-target-id'] ?? '0';

		const isValid = this.githubWebhookService.verifySignature({
			payload: rawBody,
			signature,
		});

		if (!isValid) {
			throw new UnauthorizedException('Invalid webhook signature');
		}

		const installationId = parseInt(installationIdRaw, 10);
		const payload = JSON.parse(rawBody) as unknown;

		await this.githubWebhookService.handleEvent({ event, installationId, payload });
	}
}
