import {
	Controller,
	Delete,
	Get,
	HttpCode,
	HttpStatus,
	Param,
	Post,
	Query,
	Res,
} from '@nestjs/common';
import { ApiOperation, ApiResponse, ApiTags } from '@nestjs/swagger';

import { CurrentUser } from '@modules/auth/decorators/current-user.decorator';
import { Roles } from '@modules/auth/decorators/roles.decorator';
import { IRequestUser } from '@modules/auth/types/auth.interface';
import { EnvConfigService } from '@modules/env-config/env-config.service';
import { GithubInstallService } from '@modules/github/github-install.service';

import { FRONTEND_URL } from '@constants/env-variables.constant';

import { LogExecution } from '@decorators/log-execution.decorator';

import type { FastifyReply } from 'fastify';

@ApiTags('GitHub Integration')
@Controller('integrations/github')
export class GithubInstallController {
	constructor(
		private readonly githubInstallService: GithubInstallService,
		private readonly configService: EnvConfigService,
	) {}

	@Post('connect')
	@Roles('admin')
	@HttpCode(HttpStatus.OK)
	@ApiOperation({ summary: 'Initiate GitHub App installation' })
	@ApiResponse({ status: HttpStatus.OK, description: 'Returns GitHub install URL' })
	@LogExecution()
	async connect(@CurrentUser() user: IRequestUser): Promise<{ url: string }> {
		// eslint-disable-next-line @typescript-eslint/no-non-null-assertion
		const companyId = user.company_id!;
		const url = await this.githubInstallService.initiateConnect({
			companyId,
			userId: user.user_id,
		});
		return { url };
	}

	@Get('callback')
	@Roles('admin')
	@ApiOperation({ summary: 'GitHub App installation callback' })
	@ApiResponse({ status: HttpStatus.FOUND, description: 'Redirects to frontend' })
	@LogExecution()
	async callback(
		@Query() query: { installation_id: string; state: string; setup_action: string },
		@Res() reply: FastifyReply,
	): Promise<void> {
		const frontendUrl = this.configService.get<string>({ key: FRONTEND_URL });

		try {
			await this.githubInstallService.handleCallback({
				installationId: Number(query.installation_id),
				state: query.state,
			});

			await reply.redirect(`${frontendUrl}/settings/integrations?connected=github`);
		} catch {
			await reply.redirect(
				`${frontendUrl}/settings/integrations?error=github_connect_failed`,
			);
		}
	}

	@Delete('installations/:id')
	@Roles('admin')
	@HttpCode(HttpStatus.NO_CONTENT)
	@ApiOperation({ summary: 'Disconnect GitHub installation' })
	@ApiResponse({
		status: HttpStatus.NO_CONTENT,
		description: 'Installation disconnected',
	})
	@LogExecution()
	async disconnect(
		@Param() params: { id: string },
		@CurrentUser() user: IRequestUser,
	): Promise<void> {
		// eslint-disable-next-line @typescript-eslint/no-non-null-assertion
		const companyId = user.company_id!;
		await this.githubInstallService.disconnect({
			installationDbId: params.id,
			companyId,
		});
	}
}

