import * as request from 'supertest';

import { GithubWebhookController } from '@modules/github/github-webhook.controller';
import { GithubWebhookService } from '@modules/github/github-webhook.service';

const mockWebhookService = {
  verifySignature: jest.fn(),
  handleEvent: jest.fn(),
};

describe('GithubWebhookController (e2e)', () => {
  let app: NestFastifyApplication;

  beforeAll(async () => {
    const moduleFixture: TestingModule = await Test.createTestingModule({
      controllers: [GithubWebhookController],
      providers: [{ provide: GithubWebhookService, useValue: mockWebhookService }],
    }).compile();

    app = moduleFixture.createNestApplication<NestFastifyApplication>(new FastifyAdapter());
    await app.init();
    await app.getHttpAdapter().getInstance().ready();
  });

  afterAll(async () => {
    await app.close();
  });

  beforeEach(() => jest.clearAllMocks());

  describe('POST /integrations/github/webhook', () => {
    it('should return 401 when signature is invalid', async () => {
      mockWebhookService.verifySignature.mockReturnValue(false);

      const res = await request(app.getHttpServer())
        .post('/integrations/github/webhook')
        .set('x-github-event', 'push')
        .set('x-hub-signature-256', 'sha256=invalid')
        .set('x-github-hook-installation-target-id', '12345678')
        .send('{"ref":"refs/heads/main"}');

      expect(res.status).toBe(HttpStatus.UNAUTHORIZED);
    });

    it('should return 200 when signature is valid', async () => {
      mockWebhookService.verifySignature.mockReturnValue(true);
      mockWebhookService.handleEvent.mockResolvedValue(undefined);

      const res = await request(app.getHttpServer())
        .post('/integrations/github/webhook')
        .set('x-github-event', 'push')
        .set('x-hub-signature-256', 'sha256=valid')
        .set('x-github-hook-installation-target-id', '12345678')
        .send('{"ref":"refs/heads/main"}');

      expect(res.status).toBe(HttpStatus.OK);
      expect(mockWebhookService.handleEvent).toHaveBeenCalled();
    });
  });
});
