import { randomUUID } from 'crypto';

import fastifyCookie from '@fastify/cookie';
import { HttpService } from '@nestjs/axios';
import { ValidationPipe } from '@nestjs/common';
import { FastifyAdapter, NestFastifyApplication } from '@nestjs/platform-fastify';
import { Test, TestingModule } from '@nestjs/testing';
import { Redis } from 'ioredis';
import Knex from 'knex';
import * as request from 'supertest';

import { AppModule } from '@modules/app/app.module';
import { REDIS_WRITE_CLIENT } from '@modules/cache/cache.constant';
import { GithubInstallationModel } from '@modules/github/db/github-installations.model';
import { GithubAppService } from '@modules/github/github-app.service';
import { GithubInstallationStatus } from '@modules/github/types/github-installation.interface';

import type { App } from 'supertest/types';

import {
	cleanDatabase,
	cleanRedis,
	createAccessToken,
	createSession,
	createTestUser,
	insertCompany,
	insertCompanyMember,
	insertUser,
} from './helpers/auth.helper';

async function cleanGithubTables({ knex }: { knex: Knex.Knex }): Promise<void> {
	await knex.raw('TRUNCATE TABLE github_repos, github_installations CASCADE');
}

describe('GithubModule (e2e)', () => {
	let app: NestFastifyApplication;
	let httpServer: App;
	let knex: Knex.Knex;
	let redis: Redis;
	let moduleFixture: TestingModule;
	let githubInstallationModel: GithubInstallationModel;
	let httpService: HttpService;
	let githubAppService: GithubAppService;

	beforeAll(async () => {
		moduleFixture = await Test.createTestingModule({
			imports: [AppModule],
		}).compile();

		app = moduleFixture.createNestApplication<NestFastifyApplication>(
			new FastifyAdapter(),
		);
		await app.register(fastifyCookie);

		app.useGlobalPipes(
			new ValidationPipe({
				transform: true,
				whitelist: true,
				forbidNonWhitelisted: true,
			}),
		);

		app.setGlobalPrefix('api', { exclude: ['liveness', 'readiness'] });

		await app.init();
		await app.getHttpAdapter().getInstance().ready();

		httpServer = app.getHttpServer() as App;

		knex = Knex({
			client: 'pg',
			connection: process.env['DATABASE_URL']!,
		});

		redis = moduleFixture.get<Redis>(REDIS_WRITE_CLIENT);
		httpService = moduleFixture.get<HttpService>(HttpService);
		githubAppService = moduleFixture.get<GithubAppService>(GithubAppService);
		githubInstallationModel = moduleFixture.get<GithubInstallationModel>(
			GithubInstallationModel,
		);

		await knex.migrate.latest({ directory: './src/migrations' });
	});

	afterAll(async () => {
		await cleanDatabase({ knex });
		await cleanGithubTables({ knex });
		await cleanRedis({ redis });
		await knex.destroy();
		await app.close();
	});

	beforeEach(async () => {
		await cleanDatabase({ knex });
		await cleanGithubTables({ knex });
		await cleanRedis({ redis });
		jest.restoreAllMocks();
	});

	describe('POST /api/integrations/github/connect', () => {
		it('should return 200 with GitHub install URL for admin user', async () => {
			const user = createTestUser({ email: `gh-connect-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Test Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'admin',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const res = await request(httpServer)
				.post('/api/integrations/github/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(200);
			expect(res.body).toHaveProperty('url');
			expect(res.body.url).toContain('https://github.com/apps/');
			expect(res.body.url).toContain('/installations/new?state=');
		});

		it('should return 401 when unauthenticated', async () => {
			const res = await request(httpServer)
				.post('/api/integrations/github/connect')
				.send();

			expect(res.status).toBe(401);
		});

		it('should return 403 when user has member role', async () => {
			const user = createTestUser({ email: `gh-member-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Test Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'member',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'member',
				companyId: company._id,
			});

			const res = await request(httpServer)
				.post('/api/integrations/github/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(403);
		});
	});

	describe('DELETE /api/integrations/github/installations/:id', () => {
		it('should return 204 on successful disconnect', async () => {
			const user = createTestUser({ email: `gh-disconnect-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: 'Test Company' });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'admin',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const installation = await githubInstallationModel.create({
				data: {
					company_id: company._id,
					installation_id: 99999999,
					org_login: 'test-org',
					org_id: 111111,
				},
			});

			const res = await request(httpServer)
				.delete(`/api/integrations/github/installations/${installation._id}`)
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(res.status).toBe(204);
		});

		it('should return 401 when unauthenticated', async () => {
			const res = await request(httpServer)
				.delete('/api/integrations/github/installations/some-id')
				.send();

			expect(res.status).toBe(401);
		});
	});

	describe('GithubAppService', () => {
		it('should generate a valid JWT', () => {
			const jwt = githubAppService.generateAppJwt();
			expect(typeof jwt).toBe('string');
			const parts = jwt.split('.');
			expect(parts).toHaveLength(3);
		});

		it('should return cached installation token on second call', async () => {
			jest.spyOn(httpService.axiosRef, 'post').mockResolvedValue({
				data: { token: 'test-token', expires_at: new Date().toISOString() },
				status: 201,
				statusText: 'Created',
				headers: {},
				config: { headers: {} as never },
			});

			const firstToken = await githubAppService.getInstallationToken({
				installationId: 88888888,
			});
			expect(firstToken).toBe('test-token');

			const secondToken = await githubAppService.getInstallationToken({
				installationId: 88888888,
			});
			expect(secondToken).toBe('test-token');

			expect(httpService.axiosRef.post).toHaveBeenCalledTimes(1);
		});
	});

	describe('GET /api/integrations/github/callback', () => {
		async function setupAdminUser(): Promise<{ accessToken: string; companyId: string }> {
			const user = createTestUser({ email: `gh-cb-${randomUUID()}@example.com` });
			await insertUser({ knex, user });

			const company = await insertCompany({ knex, name: `Callback Co ${randomUUID()}` });
			await insertCompanyMember({
				knex,
				userId: user._id,
				companyId: company._id,
				role: 'admin',
			});

			const sessionId = randomUUID();
			await createSession({
				redis,
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			const accessToken = createAccessToken({
				userId: user._id,
				sessionId,
				role: 'admin',
				companyId: company._id,
			});

			return { accessToken, companyId: company._id };
		}

		it('should redirect to success page when callback is valid', async () => {
			const { accessToken } = await setupAdminUser();

			const connectRes = await request(httpServer)
				.post('/api/integrations/github/connect')
				.set('Authorization', `Bearer ${accessToken}`)
				.send();

			expect(connectRes.status).toBe(200);
			const connectUrl = connectRes.body.url as string;
			const state = new URL(connectUrl).searchParams.get('state')!;

			const getSpy = jest.spyOn(httpService.axiosRef, 'get');
			getSpy.mockResolvedValueOnce({
				data: { id: 12345678, account: { login: 'acme-corp', id: 987654 } },
				status: 200,
				statusText: 'OK',
				headers: {},
				config: { headers: {} as never },
			});
			getSpy.mockResolvedValueOnce({
				data: {
					repositories: [
						{
							id: 1,
							name: 'api',
							full_name: 'acme-corp/api',
							private: true,
							default_branch: 'main',
						},
					],
					total_count: 1,
				},
				status: 200,
				statusText: 'OK',
				headers: {},
				config: { headers: {} as never },
			});
			jest.spyOn(httpService.axiosRef, 'post').mockResolvedValue({
				data: { token: 'mock-install-token', expires_at: new Date().toISOString() },
				status: 201,
				statusText: 'Created',
				headers: {},
				config: { headers: {} as never },
			});

			const res = await request(httpServer)
				.get('/api/integrations/github/callback')
				.set('Authorization', `Bearer ${accessToken}`)
				.query({ installation_id: '12345678', state, setup_action: 'install' })
				.redirects(0);

			expect(res.status).toBe(302);
			expect(res.headers['location']).toContain('/settings/integrations');
			expect(res.headers['location']).toContain('connected=github');

			await new Promise<void>((resolve) => setTimeout(resolve, 200));
		});

		it('should redirect to error page when state is invalid', async () => {
			const { accessToken } = await setupAdminUser();

			const res = await request(httpServer)
				.get('/api/integrations/github/callback')
				.set('Authorization', `Bearer ${accessToken}`)
				.query({
					installation_id: '12345678',
					state: 'invalid-state',
					setup_action: 'install',
				})
				.redirects(0);

			expect(res.status).toBe(302);
			expect(res.headers['location']).toContain('error=github_connect_failed');
		});
	});

	describe('POST /api/integrations/github/webhook', () => {
		let webhookCompanyId: string;

		beforeEach(async () => {
			const company = await insertCompany({
				knex,
				name: `Webhook Test Company ${randomUUID()}`,
			});
			webhookCompanyId = company._id;
		});

		it('should return 401 when signature is invalid', async () => {
			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'push')
				.set('x-hub-signature-256', 'sha256=invalidsignature')
				.set('x-github-hook-installation-target-id', '12345678')
				.send('{"ref":"refs/heads/main"}');

			expect(res.status).toBe(401);
		});

		it('should return 200 for valid signature when installation is unknown', async () => {
			const body = '{"ref":"refs/heads/main"}';
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const sig = `sha256=${createHmac('sha256', secret).update(body).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'push')
				.set('x-hub-signature-256', sig)
				.set('x-github-hook-installation-target-id', '99999999')
				.send(body);

			expect(res.status).toBe(200);
		});

		it('should handle installation deleted event and mark as uninstalled', async () => {
			const installation = await githubInstallationModel.create({
				data: {
					company_id: webhookCompanyId,
					installation_id: 77777777,
					org_login: 'test-org',
					org_id: 222222,
				},
			});

			const body = JSON.stringify({ action: 'deleted' });
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const sig = `sha256=${createHmac('sha256', secret).update(body).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'installation')
				.set('x-hub-signature-256', sig)
				.set('x-github-hook-installation-target-id', '77777777')
				.send(body);

			expect(res.status).toBe(200);

			await new Promise<void>((resolve) => setTimeout(resolve, 100));

			const updated = await knex('github_installations')
				.where({ installation_id: 77777777 })
				.first();
			expect(updated?.status).toBe(GithubInstallationStatus.UNINSTALLED);
			expect(updated?._id).toBe(installation._id);
		});

		it('should handle installation suspend event', async () => {
			await githubInstallationModel.create({
				data: {
					company_id: webhookCompanyId,
					installation_id: 66666666,
					org_login: 'test-org',
					org_id: 333333,
				},
			});

			const body = JSON.stringify({ action: 'suspend' });
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const sig = `sha256=${createHmac('sha256', secret).update(body).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'installation')
				.set('x-hub-signature-256', sig)
				.set('x-github-hook-installation-target-id', '66666666')
				.send(body);

			expect(res.status).toBe(200);

			await new Promise<void>((resolve) => setTimeout(resolve, 100));

			const updated = await knex('github_installations')
				.where({ installation_id: 66666666 })
				.first();
			expect(updated?.status).toBe(GithubInstallationStatus.SUSPENDED);
		});

		it('should handle installation unsuspend event', async () => {
			await githubInstallationModel.create({
				data: {
					company_id: webhookCompanyId,
					installation_id: 55555555,
					org_login: 'test-org',
					org_id: 444444,
				},
			});

			const suspendBody = JSON.stringify({ action: 'suspend' });
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const suspendSig = `sha256=${createHmac('sha256', secret).update(suspendBody).digest('hex')}`;

			await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'installation')
				.set('x-hub-signature-256', suspendSig)
				.set('x-github-hook-installation-target-id', '55555555')
				.send(suspendBody);

			const unsuspendBody = JSON.stringify({ action: 'unsuspend' });
			const unsuspendSig = `sha256=${createHmac('sha256', secret).update(unsuspendBody).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'installation')
				.set('x-hub-signature-256', unsuspendSig)
				.set('x-github-hook-installation-target-id', '55555555')
				.send(unsuspendBody);

			expect(res.status).toBe(200);

			await new Promise<void>((resolve) => setTimeout(resolve, 100));

			const updated = await knex('github_installations')
				.where({ installation_id: 55555555 })
				.first();
			expect(updated?.status).toBe(GithubInstallationStatus.ACTIVE);
		});

		it('should drop event for suspended installation', async () => {
			await githubInstallationModel.create({
				data: {
					company_id: webhookCompanyId,
					installation_id: 44444444,
					org_login: 'test-org',
					org_id: 555555,
				},
			});

			const suspendBody = JSON.stringify({ action: 'suspend' });
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const suspendSig = `sha256=${createHmac('sha256', secret).update(suspendBody).digest('hex')}`;

			await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'installation')
				.set('x-hub-signature-256', suspendSig)
				.set('x-github-hook-installation-target-id', '44444444')
				.send(suspendBody);

			const pushBody = '{"ref":"refs/heads/main"}';
			const pushSig = `sha256=${createHmac('sha256', secret).update(pushBody).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'push')
				.set('x-hub-signature-256', pushSig)
				.set('x-github-hook-installation-target-id', '44444444')
				.send(pushBody);

			expect(res.status).toBe(200);
		});

		it('should return 200 and queue event for active installation push event', async () => {
			await githubInstallationModel.create({
				data: {
					company_id: webhookCompanyId,
					installation_id: 33333333,
					org_login: 'active-org',
					org_id: 666666,
				},
			});

			const body = '{"ref":"refs/heads/main","commits":[]}';
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const sig = `sha256=${createHmac('sha256', secret).update(body).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'push')
				.set('x-hub-signature-256', sig)
				.set('x-github-hook-installation-target-id', '33333333')
				.send(body);

			expect(res.status).toBe(200);
		});

		it('should return 200 for installation event with unhandled action', async () => {
			await githubInstallationModel.create({
				data: {
					company_id: webhookCompanyId,
					installation_id: 11111111,
					org_login: 'created-org',
					org_id: 888888,
				},
			});

			const body = JSON.stringify({ action: 'new_permissions_accepted' });
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const sig = `sha256=${createHmac('sha256', secret).update(body).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'installation')
				.set('x-hub-signature-256', sig)
				.set('x-github-hook-installation-target-id', '11111111')
				.send(body);

			expect(res.status).toBe(200);
		});

		it('should return 200 when installation is in uninstalled status', async () => {
			await githubInstallationModel.create({
				data: {
					company_id: webhookCompanyId,
					installation_id: 22222222,
					org_login: 'removed-org',
					org_id: 777777,
				},
			});

			const deleteBody = JSON.stringify({ action: 'deleted' });
			const { createHmac } = await import('node:crypto');
			const secret = process.env['GITHUB_APP_WEBHOOK_SECRET']!;
			const deleteSig = `sha256=${createHmac('sha256', secret).update(deleteBody).digest('hex')}`;

			await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'installation')
				.set('x-hub-signature-256', deleteSig)
				.set('x-github-hook-installation-target-id', '22222222')
				.send(deleteBody);

			const pushBody = '{"ref":"refs/heads/main"}';
			const pushSig = `sha256=${createHmac('sha256', secret).update(pushBody).digest('hex')}`;

			const res = await request(httpServer)
				.post('/api/integrations/github/webhook')
				.set('Content-Type', 'text/plain')
				.set('x-github-event', 'push')
				.set('x-hub-signature-256', pushSig)
				.set('x-github-hook-installation-target-id', '22222222')
				.send(pushBody);

			expect(res.status).toBe(200);
		});
	});
});
